HKLM
{
    NoRemove Software
    {
        NoRemove Microsoft
        {
            NoRemove MMC
            {
                NoRemove SnapIns
                {
                    ForceRemove %VCLSID%
                    {
                        val NameString = s '%VSnapinName%'
                        val NameStringIndirect = s '%VSnapinNameIndirect%'
                    }
                }
            }
        }
    }
}

